29	static void cucp_cuup_bearer_context_setup_e1ap(sctp_assoc_t assoc_id, const e1ap_bearer_setup_req_t *req)
30	{
31	  AssertFatal(assoc_id > 0, "illegal assoc_id %d\n", assoc_id);
32	  MessageDef *msg_p = itti_alloc_new_message(TASK_CUCP_E1, 0, E1AP_BEARER_CONTEXT_SETUP_REQ);
33	  msg_p->ittiMsgHeader.originInstance = assoc_id;
34	  e1ap_bearer_setup_req_t *bearer_req = &E1AP_BEARER_CONTEXT_SETUP_REQ(msg_p);
35	  memcpy(bearer_req, req, sizeof(e1ap_bearer_setup_req_t));
36	
37	  itti_send_msg_to_task (TASK_CUCP_E1, 0, msg_p);
38	}
39	
40	static void cucp_cuup_bearer_context_mod_e1ap(sctp_assoc_t assoc_id, const e1ap_bearer_mod_req_t *req)
41	{
42	  AssertFatal(assoc_id > 0, "illegal assoc_id %d\n", assoc_id);
43	  MessageDef *msg = itti_alloc_new_message(TASK_CUCP_E1, 0, E1AP_BEARER_CONTEXT_MODIFICATION_REQ);
44	  msg->ittiMsgHeader.originInstance = assoc_id;
45	  e1ap_bearer_mod_req_t *req_msg = &E1AP_BEARER_CONTEXT_MODIFICATION_REQ(msg);
46	  memcpy(req_msg, req, sizeof(*req));
47	  itti_send_msg_to_task(TASK_CUCP_E1, 0, msg);
48	}
49	
50	static void cucp_cuup_bearer_context_release_cmd_e1ap(sctp_assoc_t assoc_id, const e1ap_bearer_release_cmd_t *cmd)
51	{
52	  AssertFatal(assoc_id > 0, "illegal assoc_id %d\n", assoc_id);
53	  MessageDef *msg = itti_alloc_new_message(TASK_CUCP_E1, 0, E1AP_BEARER_CONTEXT_RELEASE_CMD);
54	  msg->ittiMsgHeader.originInstance = assoc_id;
55	  e1ap_bearer_release_cmd_t *cmd_msg = &E1AP_BEARER_CONTEXT_RELEASE_CMD(msg);
56	  memcpy(cmd_msg, cmd, sizeof(*cmd));
57	  itti_send_msg_to_task(TASK_CUCP_E1, 0, msg);
58	}
59	
60	void cucp_cuup_message_transfer_e1ap_init(gNB_RRC_INST *rrc) {
61	  rrc->cucp_cuup.bearer_context_setup = cucp_cuup_bearer_context_setup_e1ap;
62	  rrc->cucp_cuup.bearer_context_mod = cucp_cuup_bearer_context_mod_e1ap;
63	  rrc->cucp_cuup.bearer_context_release = cucp_cuup_bearer_context_release_cmd_e1ap;
64	}

